module multiplexer(
    input [1:0] select,
    input [3:0] in,
    output reg selected_input);always @(*) begin
    case (select)
        2'd0: selected_input = in[0];
        2'd1: selected_input = in[1];
        2'd2: selected_input = in[2];
        2'd3: selected_input = in[3];
        default: selected_input = 1'b0;
    endcase
end
endmodule
